/* Apply automatic optical sizing for better readability */
body {
  font-family: 'Inter', sans-serif; /* Or any font supporting optical sizing */
  font-optical-sizing: auto;
}

/* Ensure headings also benefit from optical adjustments */
h1, h2, h3 {
  font-optical-sizing: auto;
  text-rendering: optimizeLegibility; /* Optional: Further optimize text rendering */
}
